(function () {
    const menuButton = document.querySelector('[data-menu-button]');
    const mobileMenu = document.querySelector('[data-mobile-menu]');
    if (menuButton && mobileMenu) {
        menuButton.addEventListener('click', function () {
            mobileMenu.classList.toggle('open');
        });
    }

    const slides = Array.from(document.querySelectorAll('[data-hero-slide]'));
    const dots = Array.from(document.querySelectorAll('[data-hero-dot]'));
    if (slides.length) {
        let index = 0;
        const showSlide = function (next) {
            slides[index].classList.remove('active');
            if (dots[index]) {
                dots[index].classList.remove('active');
            }
            index = (next + slides.length) % slides.length;
            slides[index].classList.add('active');
            if (dots[index]) {
                dots[index].classList.add('active');
            }
        };
        dots.forEach(function (dot, dotIndex) {
            dot.addEventListener('click', function () {
                showSlide(dotIndex);
            });
        });
        window.setInterval(function () {
            showSlide(index + 1);
        }, 5200);
    }

    const searchForm = document.querySelector('[data-search-form]');
    const searchInput = document.querySelector('[data-search-input]');
    const yearSelect = document.querySelector('[data-search-year]');
    const typeSelect = document.querySelector('[data-search-type]');
    const searchResults = document.querySelector('[data-search-results]');
    if (searchResults) {
        const render = function () {
            const q = (searchInput ? searchInput.value.trim() : '').toLowerCase();
            const year = yearSelect ? yearSelect.value : '';
            const type = typeSelect ? typeSelect.value : '';
            const matched = MovieSearchData.filter(function (item) {
                const text = [item.title, item.region, item.genre, item.oneLine, item.category].join(' ').toLowerCase();
                const okText = !q || text.indexOf(q) !== -1;
                const okYear = !year || item.year === year;
                const okType = !type || item.genre.indexOf(type) !== -1 || item.region.indexOf(type) !== -1 || item.category.indexOf(type) !== -1;
                return okText && okYear && okType;
            }).slice(0, 80);
            searchResults.innerHTML = matched.map(function (item) {
                return '<article class="movie-card compact">'
                    + '<a class="poster-link" href="./' + item.url + '">'
                    + '<img src="' + item.cover + '" alt="' + item.title.replace(/"/g, '&quot;') + '" loading="lazy">'
                    + '<span class="play-badge">播放</span></a>'
                    + '<div class="card-body"><div class="card-tags"><span>' + item.year + '</span><span>' + item.region + '</span></div>'
                    + '<h2><a href="./' + item.url + '">' + item.title + '</a></h2>'
                    + '<p>' + item.oneLine + '</p></div></article>';
            }).join('');
        };
        if (searchForm) {
            searchForm.addEventListener('submit', function (event) {
                event.preventDefault();
                render();
            });
        }
        [searchInput, yearSelect, typeSelect].forEach(function (el) {
            if (el) {
                el.addEventListener('input', render);
                el.addEventListener('change', render);
            }
        });
        render();
    }

    const player = document.querySelector('[data-player]');
    const cover = document.querySelector('[data-player-cover]');
    const source = player ? player.getAttribute('data-src') : '';
    const play = function () {
        if (!player || !source) {
            return;
        }
        if (cover) {
            cover.classList.add('hidden');
        }
        if (player.canPlayType('application/vnd.apple.mpegurl')) {
            if (player.getAttribute('src') !== source) {
                player.setAttribute('src', source);
            }
            player.play();
            return;
        }
        if (window.Hls && window.Hls.isSupported()) {
            if (!player.hlsReady) {
                const hls = new window.Hls();
                hls.loadSource(source);
                hls.attachMedia(player);
                player.hlsReady = true;
            }
            player.play();
            return;
        }
        player.setAttribute('src', source);
        player.play();
    };
    if (cover) {
        cover.addEventListener('click', play);
    }
    if (player) {
        player.addEventListener('click', function () {
            if (player.paused) {
                play();
            }
        });
        player.addEventListener('play', function () {
            if (cover) {
                cover.classList.add('hidden');
            }
        });
    }
}());
